struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id using arithmetic operator<<
        stream << packet_id;

        // Write username with prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores: first write size, then vector using stream's operator<<
        // The prefixed adaptor handles writing the size followed by the container
        stream << hexi::prefixed(scores);

        // Write metadata with null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer (std::vector<uint8_t>)
    std::vector<uint8_t> buffer;

    // Create buffer_adaptor for the buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary_stream with the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Call the packet's serialise method with the stream
    packet.serialise(stream);

    // Return the buffer containing the serialized data
    return buffer;
}
```

