#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    std::vector<uint8_t> preview_buffer(bytes_to_preview);

    // Use the copy function to preview data without advancing read pointer
    storage.copy(preview_buffer.data(), bytes_to_preview);

    return preview_buffer;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;

    // Get readable data size using size() function
    status.readable_size = storage.size();

    // Calculate free space as total capacity minus current write position
    status.free_space = 1024 - storage.write_offset;

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use clear() function to reset both read and write offsets to zero
    storage.clear();
}
```

## Explanation:

1. **preview_data_without_consuming**: 
   - Creates a destination buffer of the requested size
   - Uses the `copy` function from `intrusive_storage` which copies data without advancing the read pointer
   - Returns the populated buffer

2. **check_buffer_status**:
   - Uses `size()` function to get the amount of readable data (`write_offset - read_offset`)
   - Calculates free space as total capacity (1024) minus current write position
   - Returns a `BufferStatus` struct with both values

3. **reset_buffer**:
   - Directly calls the `clear()` function which resets both read and write offsets to zero
   - This effectively empties the buffer and makes all space available again

All functions properly utilize the provided `intrusive_storage` API as specified in the reference materials.

