#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void peek_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* data, std::size_t length) {
    // Use the non-template copy() method to copy data without advancing read pointer
    buffer.copy(data, length);
}

template<typename T>
void peek_value_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, T& value) {
    // Use the template copy() method to copy a single value without advancing read pointer
    buffer.copy(&value);
}

bool peek_and_compare(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, const void* expected, std::size_t length) {
    // Create a temporary buffer to hold the peeked data
    std::vector<std::byte> temp_buffer(length);

    // Copy data from buffer without advancing read pointer
    buffer.copy(temp_buffer.data(), length);

    // Compare the copied data with expected data
    for (std::size_t i = 0; i < length; ++i) {
        if (static_cast<const std::byte*>(expected)[i] != temp_buffer[i]) {
            return false;
        }
    }

    return true;
}
```

## Explanation:

1. **`peek_data_from_buffer`**: Uses the non-template `copy()` method that takes `void*` and `std::size_t` parameters to copy the specified number of bytes from the buffer to the destination without advancing the read pointer.

2. **`peek_value_from_buffer`**: Uses the template `copy()` method that takes a `T*` parameter to copy a single value of type `T` from the buffer without advancing the read pointer. The template automatically deduces the size using `sizeof(T)`.

3. **`peek_and_compare`**: 
   - Creates a temporary buffer to hold the data being peeked
   - Uses the non-template `copy()` method to copy data without advancing the read pointer
   - Compares each byte of the copied data with the expected data using a simple loop
   - Returns `true` if all bytes match, `false` otherwise

All implementations correctly use the `buffer_adaptor`'s `copy()` method as specified in the reference materials, ensuring that the read pointer is not advanced during the copy operations.

