    buffer.write(dummy_data.data(), dummy_data.size());

    // Return to beginning to update header
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Write header value again
    uint32_t le_header_update = std::endian::native_to_little(header_value);
    buffer.write(&le_header_update, sizeof(le_header_update));
}
